import{_ as s,c as i,o as t,a1 as a}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Superpowers Integration","description":"Learn to configure Superpowers mode for continuous AI workflow guidance.","frontmatter":{"title":"Superpowers Integration","subtitle":"Superpowers Integration","sidebarTitle":"Superpowers Integration","description":"Learn to configure Superpowers mode for continuous AI workflow guidance.","tags":["Advanced Configuration","Workflow","Superpowers"],"prerequisite":["/joshuadavidthomas/opencode-agent-skills/start-installation"],"order":2},"headers":[],"relativePath":"joshuadavidthomas/opencode-agent-skills/advanced/superpowers-integration/index.md","filePath":"joshuadavidthomas/opencode-agent-skills/advanced/superpowers-integration/index.md"}'),o={name:"joshuadavidthomas/opencode-agent-skills/advanced/superpowers-integration/index.md"};function l(n,e,r,p,d,h){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="superpowers-workflow-integration" tabindex="-1">Superpowers Workflow Integration <a class="header-anchor" href="#superpowers-workflow-integration" aria-label="Permalink to &quot;Superpowers Workflow Integration&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Understand the value and use cases of Superpowers workflow</li><li>Correctly install and configure Superpowers mode</li><li>Understand tool mapping and skill namespace system</li><li>Master the automatic injection mechanism for Superpowers during compaction recovery</li></ul><h2 id="your-current-struggle" tabindex="-1">Your Current Struggle <a class="header-anchor" href="#your-current-struggle" aria-label="Permalink to &quot;Your Current Struggle&quot;">​</a></h2><p>You may be considering these issues:</p><ul><li><strong>Inconsistent development workflow</strong>: Team members have different development habits, leading to inconsistent code quality</li><li><strong>Lack of strict process</strong>: Although you have a skill library, the AI assistant lacks clear process guidance</li><li><strong>Confused tool invocation</strong>: Tools defined by Superpowers have different names than OpenCode&#39;s native tools, causing invocation failures</li><li><strong>High migration cost</strong>: You&#39;re already using Superpowers and worry about needing to reconfigure after switching to OpenCode</li></ul><p>These issues affect development efficiency and code quality.</p><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">What is Superpowers?</p><p>Superpowers is a complete software development workflow framework that provides strict workflow guidance through composable skills. It defines standardized development steps, tool invocation methods, and a namespace system.</p></div><p><strong>OpenCode Agent Skills provides seamless Superpowers integration</strong>. When enabled via environment variables, it automatically injects complete workflow guidance, including:</p><ol><li><strong>using-superpowers skill content</strong>: Superpowers core workflow instructions</li><li><strong>Tool mapping</strong>: Maps tool names defined by Superpowers to OpenCode native tools</li><li><strong>Skill namespace</strong>: Clearly defines skill priority and reference methods</li></ol><h2 id="🎒-prerequisites" tabindex="-1">🎒 Prerequisites <a class="header-anchor" href="#🎒-prerequisites" aria-label="Permalink to &quot;🎒 Prerequisites&quot;">​</a></h2><p>Before starting, ensure:</p><div class="warning custom-block"><p class="custom-block-title">Prerequisite Check</p><ul><li>✅ <a href="./../../start/installation/">opencode-agent-skills plugin installed</a></li><li>✅ Familiar with basic skill discovery mechanism</li></ul></div><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-install-superpowers" tabindex="-1">Step 1: Install Superpowers <a class="header-anchor" href="#step-1-install-superpowers" aria-label="Permalink to &quot;Step 1: Install Superpowers&quot;">​</a></h3><p><strong>Why</strong> You need to install the Superpowers project first so that this plugin can discover the <code>using-superpowers</code> skill.</p><p><strong>How</strong></p><p>Choose one of the following installation methods based on your needs:</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-8RLnw" id="tab-CQYhuJT" checked><label data-title="As a Claude Code plugin" for="tab-CQYhuJT">As a Claude Code plugin</label><input type="radio" name="group-8RLnw" id="tab-R5CJugh"><label data-title="As an OpenCode skill" for="tab-R5CJugh">As an OpenCode skill</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">//</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> following</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Superpowers</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> official</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> documentation</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">//</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/obra/superpowers</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">//</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> will</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> be</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> automatically</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> located</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> at</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.claude/plugins/...</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">//</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Manually</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> as</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> an</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> OpenCode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skill</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/opencode/skills</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/obra/superpowers</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/opencode/skills/superpowers</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">//</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> will</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> be</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> located</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> at</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .opencode/skills/superpowers/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (project-level) or </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/.config/opencode/skills/superpowers/ (</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">user-level</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></div></div><p><strong>You should see</strong>:</p><ul><li>After installation, the Superpowers skill directory contains the <code>using-superpowers/SKILL.md</code> file</li></ul><h3 id="step-2-enable-superpowers-mode" tabindex="-1">Step 2: Enable Superpowers Mode <a class="header-anchor" href="#step-2-enable-superpowers-mode" aria-label="Permalink to &quot;Step 2: Enable Superpowers Mode&quot;">​</a></h3><p><strong>Why</strong> Tell the plugin to enable Superpowers mode through environment variables, and the plugin will automatically inject relevant content during session initialization.</p><p><strong>How</strong></p><p>Temporary enable (current terminal session only):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">true</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opencode</span></span></code></pre></div><p>Permanent enable (add to Shell configuration file):</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-Dxo9t" id="tab-IhROJ5h" checked><label data-title="Bash (~/.bashrc or ~/.bash_profile)" for="tab-IhROJ5h">Bash (~/.bashrc or ~/.bash_profile)</label><input type="radio" name="group-Dxo9t" id="tab-OkwplaF"><label data-title="Zsh (~/.zshrc)" for="tab-OkwplaF">Zsh (~/.zshrc)</label><input type="radio" name="group-Dxo9t" id="tab-VJIL8fJ"><label data-title="PowerShell (~/.config/powershell/Microsoft.PowerShell_profile.ps1)" for="tab-VJIL8fJ">PowerShell (~/.config/powershell/Microsoft.PowerShell_profile.ps1)</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;export OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE=true&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.bashrc</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.bashrc</span></span></code></pre></div><div class="language-zsh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">zsh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;export OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE=true&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.zshrc</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.zshrc</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">System.Environment</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]::SetEnvironmentVariable(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;true&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;User&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></div></div><p><strong>You should see</strong>:</p><ul><li>Input <code>echo $OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE</code> displays <code>true</code></li></ul><h3 id="step-3-verify-automatic-injection" tabindex="-1">Step 3: Verify Automatic Injection <a class="header-anchor" href="#step-3-verify-automatic-injection" aria-label="Permalink to &quot;Step 3: Verify Automatic Injection&quot;">​</a></h3><p><strong>Why</strong> Confirm that the plugin correctly identifies Superpowers skills and automatically injects content when starting a new session.</p><p><strong>How</strong></p><ol><li>Restart OpenCode</li><li>Create a new session</li><li>Enter any message in the new session (e.g., &quot;Hello&quot;)</li><li>Check session context (if OpenCode supports it)</li></ol><p><strong>You should see</strong>:</p><ul><li>The plugin automatically injected the following content in the background (formatted as XML):</li></ul><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">EXTREMELY_IMPORTANT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">You have superpowers.</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">**IMPORTANT: The using-superpowers skill content is included below. It is ALREADY LOADED - do not call use_skill for it again. Use use_skill only for OTHER skills.**</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[Actual content of using-superpowers skill...]</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">**Tool Mapping for OpenCode:**</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">- `TodoWrite` → `todowrite`</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">- `Task` tool with subagents → Use `task` tool with `subagent_type`</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">- `Skill` tool → `use_skill`</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">- `Read`, `Write`, `Edit`, `Bash`, `Glob`, `Grep`, `WebFetch` → Use native lowercase OpenCode tools</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">**Skill namespace priority:**</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">1. Project: `project:skill-name`</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">2. Claude project: `claude-project:skill-name`</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">3. User: `skill-name`</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">4. Claude user: `claude-user:skill-name`</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">5. Marketplace: `claude-plugins:skill-name`</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">The first discovered match wins.</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">EXTREMELY_IMPORTANT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><p>After completing the above steps, verify the following:</p><table tabindex="0"><thead><tr><th>Check Item</th><th>Expected Result</th></tr></thead><tbody><tr><td>Environment variable set correctly</td><td><code>echo $OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE</code> outputs <code>true</code></td></tr><tr><td>Superpowers skill discoverable</td><td>Calling <code>get_available_skills()</code> shows <code>using-superpowers</code></td></tr><tr><td>New session auto-injects</td><td>After creating a new session, the AI knows it has superpowers</td></tr></tbody></table><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><h3 id="❌-error-1-skill-not-discovered" tabindex="-1">❌ Error 1: Skill Not Discovered <a class="header-anchor" href="#❌-error-1-skill-not-discovered" aria-label="Permalink to &quot;❌ Error 1: Skill Not Discovered&quot;">​</a></h3><p><strong>Symptom</strong>: Environment variable is enabled, but the plugin doesn&#39;t inject Superpowers content.</p><p><strong>Cause</strong>: Superpowers is not installed in a skill discovery path.</p><p><strong>Solution</strong>:</p><ul><li>Confirm Superpowers is installed in one of the following locations: <ul><li><code>.claude/plugins/...</code> (Claude Code plugin cache)</li><li><code>.opencode/skills/...</code> (OpenCode skills directory)</li><li><code>~/.config/opencode/skills/...</code> (OpenCode user skills)</li><li><code>~/.claude/skills/...</code> (Claude user skills)</li></ul></li><li>Run <code>get_available_skills()</code> to verify that <code>using-superpowers</code> is in the list</li></ul><h3 id="❌-error-2-tool-invocation-fails" tabindex="-1">❌ Error 2: Tool Invocation Fails <a class="header-anchor" href="#❌-error-2-tool-invocation-fails" aria-label="Permalink to &quot;❌ Error 2: Tool Invocation Fails&quot;">​</a></h3><p><strong>Symptom</strong>: The AI attempts to invoke <code>TodoWrite</code> or <code>Skill</code> tools, but the tools don&#39;t exist.</p><p><strong>Cause</strong>: The AI didn&#39;t apply tool mapping and is still using names defined by Superpowers.</p><p><strong>Solution</strong>:</p><ul><li>The plugin automatically injects tool mapping. Ensure the <code>&lt;EXTREMELY_IMPORTANT&gt;</code> tag is correctly injected</li><li>If the problem persists, check whether the session was created after enabling the environment variable</li></ul><h3 id="❌-error-3-superpowers-disappears-after-compaction" tabindex="-1">❌ Error 3: Superpowers Disappears After Compaction <a class="header-anchor" href="#❌-error-3-superpowers-disappears-after-compaction" aria-label="Permalink to &quot;❌ Error 3: Superpowers Disappears After Compaction&quot;">​</a></h3><p><strong>Symptom</strong>: After a long session, the AI no longer follows the Superpowers workflow.</p><p><strong>Cause</strong>: Context compression cleared previously injected content.</p><p><strong>Solution</strong>:</p><ul><li>The plugin will automatically re-inject Superpowers content after the <code>session.compacted</code> event</li><li>If the problem persists, check whether the plugin is properly listening to events</li></ul><h2 id="tool-mapping-details" tabindex="-1">Tool Mapping Details <a class="header-anchor" href="#tool-mapping-details" aria-label="Permalink to &quot;Tool Mapping Details&quot;">​</a></h2><p>The plugin automatically injects the following tool mappings to help the AI correctly invoke OpenCode tools:</p><table tabindex="0"><thead><tr><th>Superpowers Tool</th><th>OpenCode Tool</th><th>Description</th></tr></thead><tbody><tr><td><code>TodoWrite</code></td><td><code>todowrite</code></td><td>Todo write tool</td></tr><tr><td><code>Task</code> (with subagents)</td><td><code>task</code> + <code>subagent_type</code></td><td>Subagent invocation</td></tr><tr><td><code>Skill</code></td><td><code>use_skill</code></td><td>Load skill</td></tr><tr><td><code>Read</code> / <code>Write</code> / <code>Edit</code></td><td>Native lowercase tools</td><td>File operations</td></tr><tr><td><code>Bash</code> / <code>Glob</code> / <code>Grep</code> / <code>WebFetch</code></td><td>Native lowercase tools</td><td>System operations</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Why do we need tool mapping?</p><p>Superpowers is natively designed based on Claude Code, and tool names are inconsistent with OpenCode. Through automatic mapping, the AI can seamlessly use OpenCode&#39;s native tools without manual conversion.</p></div><h2 id="skill-namespace-priority" tabindex="-1">Skill Namespace Priority <a class="header-anchor" href="#skill-namespace-priority" aria-label="Permalink to &quot;Skill Namespace Priority&quot;">​</a></h2><p>When skills with the same name exist from multiple sources, the plugin selects them in the following priority order:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. project:skill-name         (Project-level OpenCode skills)</span></span>\n<span class="line"><span>2. claude-project:skill-name  (Project-level Claude skills)</span></span>\n<span class="line"><span>3. skill-name                (User-level OpenCode skills)</span></span>\n<span class="line"><span>4. claude-user:skill-name    (User-level Claude skills)</span></span>\n<span class="line"><span>5. claude-plugins:skill-name (Plugin marketplace skills)</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">Namespace Reference</p><p>You can explicitly specify a namespace: <code>use_skill(&quot;project:my-skill&quot;)</code><br> Or let the plugin automatically match: <code>use_skill(&quot;my-skill&quot;)</code></p></div><p><strong>The first discovered match takes effect</strong>, and subsequent same-name skills are ignored. This allows project-level skills to override user-level skills.</p><h2 id="compaction-recovery-mechanism" tabindex="-1">Compaction Recovery Mechanism <a class="header-anchor" href="#compaction-recovery-mechanism" aria-label="Permalink to &quot;Compaction Recovery Mechanism&quot;">​</a></h2><p>In long sessions, OpenCode performs context compression to save tokens. The plugin ensures Superpowers remains available through the following mechanism:</p><ol><li><strong>Listen to events</strong>: The plugin listens for the <code>session.compacted</code> event</li><li><strong>Re-inject</strong>: After compression completes, automatically re-inject Superpowers content</li><li><strong>Seamless transition</strong>: AI&#39;s workflow guidance always exists and won&#39;t be interrupted by compression</li></ol><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Superpowers integration provides strict workflow guidance. Key points:</p><ul><li><strong>Install Superpowers</strong>: Choose either Claude Code plugin or OpenCode skill installation</li><li><strong>Enable environment variable</strong>: Set <code>OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE=true</code></li><li><strong>Auto-inject</strong>: Plugin automatically injects content during session initialization and after compression</li><li><strong>Tool mapping</strong>: Automatically maps Superpowers tool names to OpenCode native tools</li><li><strong>Namespace priority</strong>: Project-level skills take priority over user-level skills</li></ul><h2 id="preview-next-lesson" tabindex="-1">Preview: Next Lesson <a class="header-anchor" href="#preview-next-lesson" aria-label="Permalink to &quot;Preview: Next Lesson&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../namespaces-and-priority/">Namespaces and Skill Priority</a></strong>.</p><p>You will learn:</p><ul><li>Understand the skill namespace system and discovery priority rules</li><li>Master how to use namespaces to explicitly specify skill sources</li><li>Learn about override and conflict handling mechanisms for same-name skills</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Function</th><th>File Path</th><th>Line</th></tr></thead><tbody><tr><td>Superpowers integration module</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/superpowers.ts#L1-L59" target="_blank" rel="noreferrer"><code>src/superpowers.ts</code></a></td><td>1-59</td></tr><tr><td>Tool mapping definition</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/superpowers.ts#L12-L16" target="_blank" rel="noreferrer"><code>src/superpowers.ts</code></a></td><td>12-16</td></tr><tr><td>Skill namespace definition</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/superpowers.ts#L18-L25" target="_blank" rel="noreferrer"><code>src/superpowers.ts</code></a></td><td>18-25</td></tr><tr><td>Superpowers content injection function</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/superpowers.ts#L31-L58" target="_blank" rel="noreferrer"><code>src/superpowers.ts</code></a></td><td>31-58</td></tr><tr><td>Environment variable check</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/superpowers.ts#L37" target="_blank" rel="noreferrer"><code>src/superpowers.ts</code></a></td><td>37</td></tr><tr><td>Session initialization injection call</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L101" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>101</td></tr><tr><td>Re-inject after compaction</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L148" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>148</td></tr></tbody></table><p><strong>Key Constants</strong>:</p><ul><li><code>OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE</code>: Environment variable, set to <code>&#39;true&#39;</code> to enable Superpowers mode</li></ul><p><strong>Key Functions</strong>:</p><ul><li><code>maybeInjectSuperpowersBootstrap()</code>: Checks environment variables and skill existence, injects Superpowers content</li><li><code>discoverAllSkills()</code>: Discovers all available skills (used to find <code>using-superpowers</code>)</li><li><code>injectSyntheticContent()</code>: Injects content into the session as a synthetic message</li></ul></details>',77)])])}const k=s(o,[["render",l]]);export{u as __pageData,k as default};
